// Extract + Dedup v6: Handles text AND voice/audio messages
try {
  const body = $input.first().json.body;
  const entry = body?.entry?.[0];
  const messaging = entry?.messaging?.[0];

  if (!messaging) return [{ json: { skip: true, skipSend: true, reason: 'no_messaging_event' } }];
  if (messaging.delivery) return [{ json: { skip: true, skipSend: true, reason: 'delivery_receipt' } }];
  if (messaging.read) return [{ json: { skip: true, skipSend: true, reason: 'read_receipt' } }];
  if (messaging.message?.is_echo) return [{ json: { skip: true, skipSend: true, reason: 'echo_message' } }];

  const senderPsid = messaging.sender.id;
  const messageMid = messaging.message?.mid;
  const timestamp = messaging.timestamp;

  // Check for audio/voice attachment
  let hasAudio = false;
  let audioUrl = '';
  const attachments = messaging.message?.attachments || [];
  for (const att of attachments) {
    if (att.type === 'audio') {
      hasAudio = true;
      audioUrl = att.payload?.url || '';
      break;
    }
  }

  // Check for text
  const messageText = messaging.message?.text || '';

  // Skip if neither text nor audio
  if (!messageText && !hasAudio) {
    return [{ json: { skip: true, skipSend: true, reason: 'no_text_or_audio' } }];
  }

  // Deduplication using workflow static data
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.processedMids) staticData.processedMids = {};
  const now = Date.now();
  const fiveMinutes = 5 * 60 * 1000;

  // Clean old entries
  const midKeys = Object.keys(staticData.processedMids);
  if (midKeys.length > 500) {
    const sorted = midKeys.sort((a, b) => staticData.processedMids[a] - staticData.processedMids[b]);
    for (const key of sorted.slice(0, midKeys.length - 400)) { delete staticData.processedMids[key]; }
  }
  for (const key of Object.keys(staticData.processedMids)) {
    if (now - staticData.processedMids[key] > fiveMinutes) { delete staticData.processedMids[key]; }
  }

  // Check duplicate
  if (messageMid && staticData.processedMids[messageMid]) {
    return [{ json: { skip: false, skipSend: true, reason: 'duplicate', senderPsid, messageText, messageMid, timestamp } }];
  }
  if (messageMid) staticData.processedMids[messageMid] = now;

  return [{ json: { skip: false, skipSend: false, senderPsid, messageText, messageMid, timestamp, hasAudio, audioUrl } }];
} catch (err) {
  return [{ json: { skip: true, skipSend: true, reason: 'extract_error: ' + err.message } }];
}

// Handle Transcription Result v6: Extract text from Whisper response or handle failure
try {
  const data = $input.first().json;
  const prevData = $('Has Audio?').first().json;
  const senderPsid = prevData.senderPsid || '';
  const messageMid = prevData.messageMid || '';
  const timestamp = prevData.timestamp || Date.now();
  const audioUrl = prevData.audioUrl || '';

  // Debug fields
  const debug = {
    audioDetected: true,
    audioUrlFound: !!audioUrl,
    audioDownloaded: false,
    transcriptionText: '',
    transcriptionError: ''
  };

  // Check if Whisper returned a text field (successful transcription)
  const transcribedText = data.text || '';

  if (transcribedText && transcribedText.length > 0) {
    debug.audioDownloaded = true;
    debug.transcriptionText = transcribedText;
    return [{ json: {
      senderPsid,
      messageMid,
      timestamp,
      messageText: transcribedText,
      hasAudio: true,
      skipToReply: false,
      ...debug
    }}];
  }

  // Check for error responses
  const errorMsg = data.error?.message || data.message || 'No transcription text returned';
  debug.transcriptionError = errorMsg;

  // Check if download itself failed (binary data not present = download failed)
  if (data.statusCode && data.statusCode >= 400) {
    debug.transcriptionError = `HTTP ${data.statusCode}: ${errorMsg}`;
  }

  // Transcription failed
  return [{ json: {
    senderPsid,
    messageMid,
    timestamp,
    messageText: '',
    hasAudio: true,
    skipToReply: true,
    replyText: 'Voice ta clear \u09AC\u09C1\u099D\u09A4\u09C7 \u09AA\u09BE\u09B0\u09BF\u09A8\u09BF\u0964 Please text \u0995\u09B0\u09C7 \u09AC\u09B2\u09AC\u09C7\u09A8 \u0985\u09A5\u09AC\u09BE \u0986\u09AC\u09BE\u09B0 voice \u09A6\u09BF\u09A8\u0964',
    intent: 'audio_failed',
    route: 'audio_failed',
    aiUsed: false,
    skipSend: false,
    needsHumanSupport: false,
    telegramAlertText: '',
    memoryUpdate: {},
    confidence: 'low',
    ...debug
  }}];
} catch (err) {
  const prevData = $('Has Audio?').first()?.json || {};
  return [{ json: {
    senderPsid: prevData.senderPsid || '',
    messageMid: prevData.messageMid || '',
    timestamp: prevData.timestamp || Date.now(),
    messageText: '',
    hasAudio: true,
    skipToReply: true,
    replyText: 'Voice message process \u0995\u09B0\u09A4\u09C7 problem \u09B9\u09AF\u09BC\u09C7\u099B\u09C7\u0964 Text \u0995\u09B0\u09C7 \u09AC\u09B2\u09C1\u09A8\u0964',
    intent: 'audio_error',
    route: 'audio_error',
    aiUsed: false,
    skipSend: false,
    needsHumanSupport: false,
    telegramAlertText: '',
    memoryUpdate: {},
    confidence: 'low',
    audioDetected: true,
    audioUrlFound: !!prevData.audioUrl,
    audioDownloaded: false,
    transcriptionText: '',
    transcriptionError: err.message
  }}];
}

// Load Memory + Normalize v6: Typo correction, language detection, entity extraction
try {
  const input = $input.first().json;
  const senderPsid = input.senderPsid;
  const messageText = input.messageText;
  const messageMid = input.messageMid;
  const timestamp = input.timestamp;
  const hasAudio = input.hasAudio || false;

  // Load memory from workflow static data
  const staticData = $getWorkflowStaticData('global');
  const memKey = `mem_${senderPsid}`;
  const memory = staticData[memKey] || {};

  // Typo normalization map
  const typoMap = {
    'delivry': 'delivery', 'dilevary': 'delivery', 'delevery': 'delivery',
    'retrn': 'return', 'retun': 'return',
    'exchng': 'exchange', 'excange': 'exchange',
    'tshart': 't-shirt', 't-shart': 't-shirt', 't shirt': 't-shirt',
    'hudie': 'hoodie', 'hudi': 'hoodie',
    'jins': 'jeans', 'jeens': 'jeans',
    'prize': 'price',
    'availble': 'available', 'avilable': 'available',
    'dhaka city': 'inside_dhaka', 'inside dhaka': 'inside_dhaka', 'dhakar vitore': 'inside_dhaka',
    'baire dhaka': 'outside_dhaka', 'outside dhaka': 'outside_dhaka', 'dhakar baire': 'outside_dhaka'
  };

  let normalizedMessage = messageText.toLowerCase().trim();
  for (const [typo, fix] of Object.entries(typoMap)) {
    normalizedMessage = normalizedMessage.replace(new RegExp(typo, 'gi'), fix);
  }

  // Language detection
  const banglaRegex = /[\u0980-\u09FF]/;
  const banglishWords = ['ki','kemon','ache','chai','korbo','hobe','diben','koto','dam','poro','eid','salam','bhai','apa','vai','dada','onek','sundor','valo','kobe','pathaben','lagbe','dorkar','apni','ami','kori','korte','bolte','jante','dekhte','kinbo','nibo'];
  let languageStyle = 'english';
  if (banglaRegex.test(messageText)) {
    languageStyle = 'bangla';
  } else {
    const words = normalizedMessage.split(/\s+/);
    if (words.some(w => banglishWords.includes(w)) || /\b(er|ta|tay|te|gulo|gulor)\b/.test(normalizedMessage)) {
      languageStyle = 'banglish';
    }
  }

  // Entity extraction
  let extractedBudget = null;
  const budgetMatch = normalizedMessage.match(/(\d+)\s*(bdt|taka|tk|\u09F3)|under\s*(\d+)|(\d+)\s*er\s*moddhe/i);
  if (budgetMatch) {
    extractedBudget = parseInt(budgetMatch[1] || budgetMatch[3] || budgetMatch[4]);
  }

  let extractedSize = null;
  const sizeMatch = normalizedMessage.match(/\b(xxl|xl|l|m|s)\b/i);
  const heightMatch = normalizedMessage.match(/(\d+)\s*(feet|ft|foot|\')|(\d+)\s*(inch|in|\")/i);
  const weightMatch = normalizedMessage.match(/(\d+)\s*(kg|kilo)/i);
  if (sizeMatch) extractedSize = sizeMatch[1].toUpperCase();
  else if (heightMatch || weightMatch) extractedSize = 'needs_calculation';

  let extractedColor = null;
  const colors = ['black','white','red','blue','green','navy','grey','gray','maroon','olive','beige','cream','pink','yellow','orange','purple','brown','kalo','sada','lal','nil','sobuj'];
  for (const c of colors) {
    if (normalizedMessage.includes(c)) { extractedColor = c; break; }
  }

  let extractedOccasion = null;
  const occasions = ['eid','party','office','casual','wedding','gift','puja','concert','date','interview','formal'];
  for (const o of occasions) {
    if (normalizedMessage.includes(o)) { extractedOccasion = o; break; }
  }

  return [{ json: {
    senderPsid,
    messageMid,
    customerMessage: messageText,
    normalizedMessage,
    languageStyle,
    extractedBudget,
    extractedSize,
    extractedColor,
    extractedOccasion,
    memory,
    timestamp,
    hasAudio
  }}];
} catch (err) {
  const input = $input.first()?.json || {};
  return [{ json: {
    senderPsid: input.senderPsid || '',
    messageMid: input.messageMid || '',
    customerMessage: input.messageText || '',
    normalizedMessage: (input.messageText || '').toLowerCase(),
    languageStyle: 'english',
    extractedBudget: null,
    extractedSize: null,
    extractedColor: null,
    extractedOccasion: null,
    memory: {},
    timestamp: input.timestamp || Date.now(),
    hasAudio: input.hasAudio || false
  }}];
}

// Decision Engine v6: Main routing logic with priority-based intent matching, short mixed Bangla+English replies
try {
  const normalizedData = $('Load Memory + Normalize').first().json;
  const { senderPsid, messageMid, customerMessage, normalizedMessage, languageStyle, extractedBudget, extractedSize, extractedColor, extractedOccasion, memory } = normalizedData;

  const faqRows = $('Read FAQ Sheet').all().map(i => i.json);
  const productRows = $('Read Products Sheet').all().map(i => i.json);
  const sizeGuideRows = $('Read Size Guide').all().map(i => i.json);
  const objectionRows = $('Read Sales Objections').all().map(i => i.json);

  const words = normalizedMessage.split(/\s+/);
  const wordCount = words.length;
  const canonical = (extra) => ({ senderPsid, messageMid, customerMessage, normalizedMessage, languageStyle, extractedBudget, extractedSize, extractedColor, extractedOccasion, memory, needsHumanSupport: false, telegramAlertText: '', memoryUpdate: {}, skipSend: false, aiUsed: false, confidence: 'high', ...extra });

  // --- a) GREETING / THANKS / BYE (words<=4) ---
  const greetings = ['assalamualaikum','salam','walaikum','hi','hello','hey','hola','yo','sup','kemon','kemn'];
  const thanksWords = ['thanks','thank','thankyou','thx','jazakallah','shukria','dhonnobad'];
  const byeWords = ['bye','goodbye','later','seeya','cya','allah hafez','khuda hafez'];
  if (wordCount <= 4) {
    if (words.some(w => greetings.includes(w))) {
      const reply = languageStyle === 'english' ? 'Hello! What are you looking for?' : 'Walaikumussalam! \u0995\u09BF \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8 \u0986\u099C?';
      return [{ json: canonical({ intent: 'greeting', replyText: reply, route: 'greeting' }) }];
    }
    if (words.some(w => thanksWords.includes(w))) {
      const reply = 'Welcome! \u0986\u09B0 \u0995\u09BF\u099B\u09C1 \u09B2\u09BE\u0997\u09B2\u09C7 \u09AC\u09B2\u09AC\u09C7\u09A8\u0964';
      return [{ json: canonical({ intent: 'thanks', replyText: reply, route: 'thanks' }) }];
    }
    if (words.some(w => byeWords.includes(w))) {
      const reply = 'Allah hafez! \u0986\u09AC\u09BE\u09B0 \u0986\u09B8\u09AC\u09C7\u09A8\u0964';
      return [{ json: canonical({ intent: 'bye', replyText: reply, route: 'bye' }) }];
    }
  }

  // --- b) HUMAN SUPPORT ---
  const supportWords = ['human','agent','person','speak to','talk to','complaint','refund','fraud','wrong item','damaged','manush','kotha bolte chai'];
  const angryPattern = (customerMessage === customerMessage.toUpperCase() && customerMessage.length > 10);
  if (supportWords.some(w => normalizedMessage.includes(w)) || angryPattern) {
    const reply = '\u09AC\u09C1\u099D\u09A4\u09C7 \u09AA\u09BE\u09B0\u099B\u09BF\u0964 Team 2-4 \u0998\u09A8\u09CD\u099F\u09BE\u09AF\u09BC contact \u0995\u09B0\u09AC\u09C7\u0964';
    const alertText = `SUPPORT REQUEST\nPSID: ${senderPsid}\nMessage: ${customerMessage}\nLanguage: ${languageStyle}\nReason: customer_requested_or_angry`;
    return [{ json: canonical({ intent: 'human_support', replyText: reply, needsHumanSupport: true, telegramAlertText: alertText, route: 'human_support' }) }];
  }

  // --- c) ORDER TRACKING ---
  const trackWords = ['track','tracking','where is my order','order status','delivery status','order kothay','parcel'];
  const orderIdMatch = customerMessage.match(/ORD-[\w-]+/i);
  if (trackWords.some(w => normalizedMessage.includes(w)) || orderIdMatch) {
    let reply;
    if (orderIdMatch) {
      const id = orderIdMatch[0].toUpperCase();
      reply = `Order ${id} check \u0995\u09B0\u099B\u09BF\u0964 Team update \u09A6\u09BF\u09AC\u09C7 shortly\u0964`;
    } else {
      reply = 'Order number \u099F\u09BE \u09A6\u09BF\u09A8 (ORD-YYYYMMDD-XXX format)\u0964';
    }
    return [{ json: canonical({ intent: 'order_tracking', replyText: reply, route: 'order_tracking' }) }];
  }

  // --- d) STYLE/OCCASION RECOMMENDATION (BEFORE order) ---
  const styleWords = ['stylish','style','outfit','look','recommend','suggest','ki porbo','what should i wear','eid er jonno','gift er jonno','casual look','party','office look','occasion'];
  if (styleWords.some(w => normalizedMessage.includes(w)) || extractedOccasion) {
    const activeProducts = productRows.filter(p => String(p.Active || '').toUpperCase() === 'YES');
    let matched = [];
    const occ = extractedOccasion || '';
    for (const p of activeProducts) {
      const tags = ((p.Occasion_Tags || '') + ' ' + (p.Style_Tags || '')).toLowerCase();
      if (occ && tags.includes(occ)) matched.push(p);
      else if (styleWords.some(w => tags.includes(w))) matched.push(p);
    }
    matched = matched.slice(0, 3);
    let reply;
    if (matched.length > 0) {
      const items = matched.map((p, i) => `${i+1}. ${p.Product_Name} - \u09F3${p.Price}`).join('\n');
      reply = `${items}\n\u0995\u09CB\u09A8\u099F\u09BE \u09AA\u099B\u09A8\u09CD\u09A6?`;
    } else {
      reply = '\u0995\u09BF \u09A7\u09B0\u09A3\u09C7\u09B0 look \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8? Casual, formal \u09A8\u09BE\u0995\u09BF Eid special?';
    }
    return [{ json: canonical({ intent: 'style_recommendation', confidence: matched.length > 0 ? 'high' : 'medium', replyText: reply, route: 'style_recommendation', memoryUpdate: { lastIntent: 'style', lastOccasion: occ } }) }];
  }

  // --- e) SIZE RECOMMENDATION ---
  const sizeWords = ['size guide','kon size','height','weight','oversized','m hobe','size chart'];
  if (sizeWords.some(w => normalizedMessage.includes(w)) || (extractedSize && extractedSize === 'needs_calculation')) {
    const heightM = normalizedMessage.match(/(\d+)\s*(?:feet|ft|foot|\')/i);
    const weightM = normalizedMessage.match(/(\d+)\s*(?:kg|kilo)/i);
    if (heightM && weightM && sizeGuideRows.length > 0) {
      const h = parseInt(heightM[1]);
      const w = parseInt(weightM[1]);
      let recommended = 'M';
      for (const row of sizeGuideRows) {
        const minH = parseInt(row.Min_Height_Feet || 0);
        const maxH = parseInt(row.Max_Height_Feet || 99);
        const minW = parseInt(row.Min_Weight_Kg || 0);
        const maxW = parseInt(row.Max_Weight_Kg || 999);
        if (h >= minH && h <= maxH && w >= minW && w <= maxW) { recommended = row.Size || 'M'; break; }
      }
      const reply = `\u0986\u09AA\u09A8\u09BE\u09B0 \u099C\u09A8\u09CD\u09AF ${recommended} size recommend \u0995\u09B0\u099B\u09BF\u0964 \u0995\u09BF product \u09A6\u09C7\u0996\u09AC\u09C7\u09A8?`;
      return [{ json: canonical({ intent: 'size_recommendation', replyText: reply, route: 'size_recommendation', memoryUpdate: { lastSize: recommended } }) }];
    } else {
      const reply = 'Size recommend \u0995\u09B0\u09A4\u09C7 height (feet) \u0986\u09B0 weight (kg) \u09AC\u09B2\u09C1\u09A8\u0964';
      return [{ json: canonical({ intent: 'size_recommendation', confidence: 'medium', replyText: reply, route: 'size_recommendation' }) }];
    }
  }

  // --- f) OBJECTION HANDLING ---
  const objectionWords = ['dam beshi','last price','discount','quality kemon','fabric kemon','original','expensive','cheap'];
  if (objectionWords.some(w => normalizedMessage.includes(w))) {
    let matchedObj = null;
    for (const obj of objectionRows) {
      const keywords = (obj.Keywords || '').toLowerCase().split(',').map(k => k.trim());
      if (keywords.some(k => normalizedMessage.includes(k))) { matchedObj = obj; break; }
    }
    let reply;
    if (matchedObj && matchedObj.Response) {
      reply = matchedObj.Response;
    } else {
      reply = 'Premium quality, value for money\u0964 Budget \u09AC\u09B2\u09B2\u09C7 match \u0995\u09B0\u09C7 \u09A6\u09C7\u0987\u0964';
    }
    return [{ json: canonical({ intent: 'objection_handling', replyText: reply, route: 'objection_handling' }) }];
  }

  // --- g) STRONG ORDER INTENT (with memory context) ---
  const strongOrderWords = ['buy','order now','place order','confirm order','checkout','eta nibo','ami nibo','ei product ta nibo','order korte chai','book this','confirm kore din','kinbo'];
  const weakWords = ['need','want','chai','lagbe','something','i need','i want','kichu','dekhan','suggest koren'];
  const hasStrongOrder = strongOrderWords.some(w => normalizedMessage.includes(w));
  const hasProductContext = memory.lastProduct || extractedColor || (extractedSize && extractedSize !== 'needs_calculation') || productRows.some(p => normalizedMessage.includes((p.Product_Name || '').toLowerCase().split(' ')[0]));
  if (hasStrongOrder) {
    if (hasProductContext || memory.lastProduct) {
      const reply = '\u09A0\u09BF\u0995 \u0986\u099B\u09C7\u0964 Size, colour \u0986\u09B0 delivery address \u09A6\u09BF\u09AC\u09C7\u09A8?';
      return [{ json: canonical({ intent: 'order_create', replyText: reply, route: 'order_intent', memoryUpdate: { lastIntent: 'order' } }) }];
    } else {
      const reply = '\u0995\u09CB\u09A8 product \u099F\u09BE \u09A8\u09BF\u09AC\u09C7\u09A8? Name \u09AC\u09B2\u09B2\u09C7 order start \u0995\u09B0\u099B\u09BF\u0964';
      return [{ json: canonical({ intent: 'order_create', confidence: 'medium', replyText: reply, route: 'order_intent' }) }];
    }
  }

  // --- h) FAQ MATCH ---
  const activeFaqs = faqRows.filter(f => String(f.Active || '').toUpperCase() === 'YES');
  const filteredWords = words.filter(w => w.length > 2).filter(w => !['the','and','for','are','this','that','with','have','show','want','your','what','does','come','any','can','you','please','hello','much','how','there'].includes(w));
  let bestFaq = null; let bestFaqScore = 0;
  for (const faq of activeFaqs) {
    const faqKeywords = (faq.Keywords || '').toLowerCase().split(',').map(k => k.trim());
    const questionWords = (faq.Question || '').toLowerCase().split(/\s+/);
    let score = 0;
    for (const word of filteredWords) {
      if (faqKeywords.some(k => k.includes(word) || word.includes(k))) score += 2;
      if (questionWords.includes(word)) score += 1;
    }
    if (score > bestFaqScore) { bestFaqScore = score; bestFaq = faq; }
  }
  if (bestFaq && bestFaqScore >= 3) {
    let faqAnswer = bestFaq.Answer || '';
    if (normalizedMessage.includes('inside_dhaka') && faqAnswer.includes('inside_dhaka')) {
      const parts = faqAnswer.split(/inside_dhaka[:\s]*/i);
      if (parts[1]) faqAnswer = parts[1].split(/outside_dhaka|\n/i)[0].trim();
    }
    return [{ json: canonical({ intent: 'faq', replyText: faqAnswer, route: 'faq_match' }) }];
  }

  // --- i) PRODUCT MATCH ---
  const activeProducts = productRows.filter(p => String(p.Active || '').toUpperCase() === 'YES');
  const scored = activeProducts.map(product => {
    const searchable = [product.Product_Name||'', product.Category||'', product.Description||'', product.Size||'', product.Color||'', product.Search_Keywords||'', product.Occasion_Tags||'', product.Style_Tags||''].join(' ').toLowerCase();
    let score = 0;
    for (const term of filteredWords) { if (searchable.includes(term)) score++; }
    if (String(product.Is_Featured || '').toUpperCase() === 'YES') score += 0.5;
    if (extractedBudget && parseInt(product.Price) > extractedBudget) score -= 2;
    return { ...product, score };
  }).filter(p => p.score > 0);

  const grouped = {};
  for (const m of scored) {
    const pid = m.Product_ID;
    if (!grouped[pid]) { grouped[pid] = { Product_ID: pid, Product_Name: m.Product_Name, Price: m.Price, Currency: m.Currency||'BDT', sizes: [], colors: [], inStock: 0, topScore: 0, Stock_Qty: 999 }; }
    if (m.score > grouped[pid].topScore) grouped[pid].topScore = m.score;
    const qty = parseInt(m.Stock_Qty || 999);
    if (qty < grouped[pid].Stock_Qty) grouped[pid].Stock_Qty = qty;
    if (String(m.In_Stock || '').toUpperCase() === 'YES') {
      grouped[pid].inStock++;
      if (m.Size && !grouped[pid].sizes.includes(m.Size)) grouped[pid].sizes.push(m.Size);
      if (m.Color && !grouped[pid].colors.includes(m.Color)) grouped[pid].colors.push(m.Color);
    }
  }
  const results = Object.values(grouped).sort((a,b) => { if (b.inStock !== a.inStock) return b.inStock > 0 ? 1 : -1; return b.topScore - a.topScore; }).slice(0, 3);

  if (results.length > 0) {
    const items = results.map((p, i) => `${i+1}. ${p.Product_Name} - \u09F3${p.Price} (Size: ${p.sizes.join(',') || 'N/A'})`).join('\n');
    const reply = `${items}\nSize/colour \u09AC\u09B2\u09B2\u09C7 exact stock check \u0995\u09B0\u09C7 \u09A6\u09BF\u09A4\u09C7 \u09AA\u09BE\u09B0\u09BF\u0964`;
    return [{ json: canonical({ intent: 'product_inquiry', replyText: reply, route: 'product_match', memoryUpdate: { lastIntent: 'product_browse', lastProduct: results[0].Product_Name } }) }];
  }

  // --- j) UNCLEAR MESSAGE (vague with only weak words, no specifics) ---
  const vagueOnly = words.every(w => weakWords.includes(w) || w.length <= 2 || ['kichu','dorkar','please','eki','ektu','show','me','give','koren','den','din'].includes(w));
  if (vagueOnly && !extractedColor && !extractedSize && !extractedOccasion && !extractedBudget && wordCount <= 6) {
    const reply = '\u0995\u09BF type item \u099A\u09BE\u09A8? T-shirt, hoodie, jeans \u09A8\u09BE\u0995\u09BF dress?';
    return [{ json: canonical({ intent: 'unclear', confidence: 'medium', replyText: reply, route: 'unclear_message' }) }];
  }

  // --- k) AI FALLBACK ---
  const categories = [...new Set(activeProducts.map(p => p.Category).filter(Boolean))].slice(0, 6).join(', ');
  return [{ json: canonical({ intent: 'complex_question', confidence: 'low', replyText: '', route: 'ai_fallback', aiUsed: true, availableCategories: categories }) }];

} catch (err) {
  const nd = $('Load Memory + Normalize').first()?.json || {};
  return [{ json: { senderPsid: nd.senderPsid || '', messageMid: nd.messageMid || '', customerMessage: nd.customerMessage || '', normalizedMessage: nd.normalizedMessage || '', languageStyle: nd.languageStyle || 'english', intent: 'error', confidence: 'low', replyText: 'Problem \u09B9\u09AF\u09BC\u09C7\u099B\u09C7\u0964 \"human\" \u09B2\u09BF\u0996\u09C1\u09A8, team help \u0995\u09B0\u09AC\u09C7\u0964', needsHumanSupport: true, telegramAlertText: 'ERROR in Decision Engine: ' + err.message, memoryUpdate: {}, skipSend: false, aiUsed: false, route: 'error', extractedBudget: null, extractedSize: null, extractedColor: null, extractedOccasion: null, memory: {} } }];
}

// Prepare Final Reply v6: Enforce short replies
try {
  const data = $input.first().json;
  let replyText = '';
  let senderPsid = data.senderPsid || '';

  if (data.replyText && data.replyText.length > 0) {
    replyText = data.replyText;
  } else if (data.output && typeof data.output === 'string' && data.output.length > 0) {
    replyText = data.output;
  } else if (data.text && typeof data.text === 'string' && data.text.length > 0) {
    replyText = data.text;
  } else if (data.response && typeof data.response === 'string' && data.response.length > 0) {
    replyText = data.response;
  } else {
    replyText = '\u0995\u09BF\u099B\u09C1 \u09AC\u09C1\u099D\u09A4\u09C7 \u09AA\u09BE\u09B0\u09BF\u09A8\u09BF\u0964 \"human\" \u09B2\u09BF\u0996\u09B2\u09C7 team connect \u0995\u09B0\u09C7 \u09A6\u09BF\u09AC\u0964';
  }

  if (!senderPsid) {
    try { senderPsid = $('Decision Engine v6').first().json.senderPsid || ''; } catch(e) {}
  }

  // Enforce max length for Messenger
  if (replyText.length > 1950) {
    replyText = replyText.substring(0, 1947) + '...';
  }

  return [{ json: {
    senderPsid,
    replyText,
    needsHumanSupport: data.needsHumanSupport || false,
    telegramAlertText: data.telegramAlertText || '',
    skipSend: data.skipSend || false,
    memoryUpdate: data.memoryUpdate || {},
    intent: data.intent || 'unknown',
    route: data.route || 'unknown',
    aiUsed: data.aiUsed || false,
    messageMid: data.messageMid || '',
    confidence: data.confidence || 'medium'
  }}];
} catch (err) {
  return [{ json: {
    senderPsid: '',
    replyText: 'Problem \u09B9\u09AF\u09BC\u09C7\u099B\u09C7\u0964 \"human\" \u09B2\u09BF\u0996\u09C1\u09A8, team help \u0995\u09B0\u09AC\u09C7\u0964',
    needsHumanSupport: true,
    telegramAlertText: 'ERROR in Prepare Final Reply: ' + err.message,
    skipSend: false,
    memoryUpdate: {},
    intent: 'error',
    route: 'error',
    aiUsed: false,
    messageMid: '',
    confidence: 'low'
  }}];
}

// Update Memory + Log v6: Persist memory updates to workflow static data
try {
  const data = $input.first().json;
  const senderPsid = data.senderPsid;
  const memoryUpdate = data.memoryUpdate || {};

  if (senderPsid && Object.keys(memoryUpdate).length > 0) {
    const staticData = $getWorkflowStaticData('global');
    const memKey = `mem_${senderPsid}`;
    if (!staticData[memKey]) staticData[memKey] = {};

    // Apply updates
    for (const [key, value] of Object.entries(memoryUpdate)) {
      staticData[memKey][key] = value;
    }
    staticData[memKey].lastActive = Date.now();
    staticData[memKey].lastIntent = data.intent || staticData[memKey].lastIntent;
    staticData[memKey].lastMessage = data.customerMessage || staticData[memKey].lastMessage;
    staticData[memKey].updatedAt = new Date().toISOString();

    // Clean old memory entries (>7 days)
    const sevenDays = 7 * 24 * 60 * 60 * 1000;
    const now = Date.now();
    for (const key of Object.keys(staticData)) {
      if (key.startsWith('mem_') && staticData[key].lastActive && (now - staticData[key].lastActive > sevenDays)) {
        delete staticData[key];
      }
    }
  }

  return [{ json: data }];
} catch (err) {
  // Memory update failure should not block the reply
  return [{ json: $input.first().json }];
}

// Mark Processed v6: Mark messageMid as processed after successful send
try {
  const data = $input.first().json;
  const messageMid = data.messageMid || $('Decision Engine v6').first()?.json?.messageMid;

  if (messageMid) {
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.processedMids) staticData.processedMids = {};
    staticData.processedMids[messageMid] = Date.now();
  }

  return [{ json: data }];
} catch (err) {
  return [{ json: $input.first().json }];
}

// Prepare Telegram Alert v6: Format alert message for Telegram
try {
  const data = $input.first().json;
  const timestamp = new Date().toISOString().replace('T', ' ').substring(0, 19);
  const memorySummary = JSON.stringify(data.memoryUpdate || {}).substring(0, 200);

  const telegramMessage = `<b>HUMAN SUPPORT NEEDED</b>\n\n` +
    `<b>PSID:</b> ${data.senderPsid || 'unknown'}\n` +
    `<b>Message ID:</b> ${data.messageMid || 'N/A'}\n` +
    `<b>Customer Message:</b> ${(data.customerMessage || data.replyText || '').substring(0, 300)}\n` +
    `<b>Language:</b> ${data.languageStyle || 'unknown'}\n` +
    `<b>Intent:</b> ${data.intent || 'unknown'}\n` +
    `<b>Confidence:</b> ${data.confidence || 'unknown'}\n` +
    `<b>Reason:</b> ${data.telegramAlertText || 'human_support_triggered'}\n` +
    `<b>Memory:</b> ${memorySummary}\n` +
    `<b>Time:</b> ${timestamp}`;

  return [{ json: { ...data, telegramMessage } }];
} catch (err) {
  const data = $input.first()?.json || {};
  return [{ json: { ...data, telegramMessage: `ALERT ERROR: ${err.message}\nPSID: ${data.senderPsid || 'unknown'}` } }];
}
